use std::rc::{Rc, Weak};
use std::cell::RefCell;

struct Node {
    name: String,
    // Use Weak for the back-pointer (the side that completes the cycle)
    neighbor_weak: Option<Weak<RefCell<Node>>>,
    // Keep a strong reference to the forward neighbor if necessary, but for simplicity,
    // we'll just use one field representing the connection.
    forward_neighbor: Option<Rc<RefCell<Node>>>
}
impl Node {
    fn new(name: &str) -> Rc<RefCell<Self>> {
        Rc::new(RefCell::new(Node {
            name: name.to_string(),
            neighbor_weak: None,
            forward_neighbor: None,
        }))
    }

    // Sets the forward link (strong ownership)
    fn set_forward_neighbor(&mut self, neighbor_rc: Rc<RefCell<Node>>) {
        self.forward_neighbor = Some(Rc::clone(&neighbor_rc));
    }

    // Sets the back link using Weak to break potential cycles
    fn set_back_neighbor(&mut self, neighbor_rc: &Rc<RefCell<Node>>) {
        self.neighbor_weak = Some(Rc::downgrade(neighbor_rc));
    }
}

fn main() {
    // 1. Create the initial nodes
    let node_a = Node::new("A");
    let node_b = Node::new("B");

    // 2. Set up A -> B link (Strong)
    node_a.borrow_mut().set_forward_neighbor(Rc::clone(&node_b));

    // 3. Create the cycle: B points back to A using Weak (Correctly breaking the cycle)
    node_b.borrow_mut().set_back_neighbor(&node_a);

    // To complete the bidirectional setup, we also link A's weak side to B.
    node_a.borrow_mut().set_back_neighbor(&node_b);

    println!("Successfully set up nodes in a graph structure using Weak pointers to prevent memory leaks.");
    // When main exits, the Rc counts drop correctly because the back-pointers use Weak.
}

use std::sync::{Arc, Mutex};

struct Counter {
    value: i32,
}

fn main() {
    // Initialize the shared state wrapped in Arc and Mutex for thread safety
    let counter = Arc::new(Mutex::new(Counter { value: 0 }));

    // Clone the Arc handle to pass ownership to a new scope/thread concept
    let counter_clone = Arc::clone(&counter);

    println!("Initial count: {}", counter.lock().unwrap().value);

    // Simulate work by acquiring the lock and modifying the state
    { 
        let mut data = counter_clone.lock().unwrap();
        data.value += 1;
        println!("Incremented locally to: {}", data.value);
    }

    // Another thread/scope can now access the updated state
    { 
        let mut data = counter_clone.lock().unwrap();
        data.value += 1;
        println!("Final count after second access: {}", data.value);
    }

    // When main exits, all Arcs are dropped, and the memory is reclaimed.
}

