    fn new(id: i32) -> Rc<Self> {
        Rc::new(Node {
            id,
            neighbors: Rc::new(RefCell::new(Vec::new())), 
        })
    }

    // Adds a connection from self to another node.
    fn add_neighbor(&self, other: Rc<Self>) {
        self.neighbors.borrow_mut().push(other.clone());
    }
}

